     1→"use client";
     2→
     3→import useSWR from "swr";
     4→import Link from "next/link";
     5→import { useState } from "react";
     6→import { useRouter } from "next/navigation";
     7→import {
     8→  projects as projectsApi,
     9→  sources as sourcesApi,
    10→  contextSources as ctxApi,
    11→  semanticReleases as srApi,
    12→  agent as agentApi,
    13→} from "@/lib/api/client";
    14→import type { AgentRules } from "@/lib/api/types";
    15→import { ProviderBadge } from "@/components/ui/provider-badge";
    16→import { StatusDot } from "@/components/ui/status-dot";
    17→import { VersionChip } from "@/components/ui/version-chip";
    18→import { SectionLabel } from "@/components/ui/section-label";
    19→import { Pencil, Trash2, Play, Plus } from "lucide-react";
    20→
    21→/* ---------- Tabs ---------- */
    22→
    23→const tabs = [
    24→  { key: "sources", label: "Sources" },
    25→  { key: "context", label: "Context Sources" },
    26→  { key: "semantic", label: "Semantic Releases" },
    27→  { key: "agent", label: "Agent" },
    28→] as const;
    29→
    30→type TabKey = (typeof tabs)[number]["key"];
    31→
    32→/* ---------- Helpers ---------- */
    33→
    34→function formatDuration(startedAt?: string, completedAt?: string): string {
    35→  if (!startedAt) return "--";
    36→  const start = new Date(startedAt).getTime();
    37→  const end = completedAt ? new Date(completedAt).getTime() : Date.now();
    38→  const secs = Math.round((end - start) / 1000);
    39→  if (secs < 60) return `${secs}s`;
    40→  const mins = Math.floor(secs / 60);
    41→  const rem = secs % 60;
    42→  return `${mins}m ${rem}s`;
    43→}
    44→
    45→function truncate(str: string, max: number): string {
    46→  return str.length > max ? str.slice(0, max) + "\u2026" : str;
    47→}
    48→
    49→function formatInterval(seconds: number): string {
    50→  if (seconds < 60) return `${seconds}s`;
    51→  if (seconds < 3600) return `${Math.round(seconds / 60)}m`;
    52→  return `${(seconds / 3600).toFixed(1)}h`;
    53→}
    54→
    55→/* ---------- Urgency chip ---------- */
    56→
    57→const URGENCY_COLORS: Record<string, { bg: string; text: string }> = {
    58→  critical: { bg: "#dc2626", text: "#ffffff" },
    59→  high: { bg: "#f97316", text: "#ffffff" },
    60→};
    61→
    62→function UrgencyChip({ urgency }: { urgency: string }) {
    63→  const u = urgency.toLowerCase();
    64→  const style = URGENCY_COLORS[u];
    65→  if (!style) return null;
    66→  return (
    67→    <span
    68→      className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium leading-none"
    69→      style={{ backgroundColor: style.bg, color: style.text }}
    70→    >
    71→      {urgency}
    72→    </span>
    73→  );
    74→}
    75→
    76→/* ---------- Main component ---------- */
    77→
    78→export function ProjectDetail({ id }: { id: string }) {
    79→  const router = useRouter();
    80→  const [activeTab, setActiveTab] = useState<TabKey>("sources");
    81→  const [triggering, setTriggering] = useState(false);
    82→
    83→  /* Agent config local state */
    84→  const [promptDraft, setPromptDraft] = useState<string | null>(null);
    85→  const [rulesDraft, setRulesDraft] = useState<AgentRules | null>(null);
    86→  const [saving, setSaving] = useState(false);
    87→
    88→  /* Data fetching */
    89→  const { data, isLoading, mutate: mutateProject } = useSWR(`project-${id}`, () => projectsApi.get(id));
    90→  const { data: sourcesData, mutate: mutateSources } = useSWR(
